>     */<br>    protected $oauthUserEmail = '';<br><br>    /**<br>     * The client secret, generated in the app definition of the service you're connecting to.<br>     *<br>     * @var string<br>     */<br>    protected $oauthClientSecret = '';<br><br>    /**<br>     * The client ID, generated in the app definition of the service you're connecting to.<br>     *<br>     * @var string<br>     */<br>    protected $oauthClientId = '';<br><br>    /**<br>     * The refresh token, used to obtain new AccessTokens.<br>     *<br>     * @var string<br>     */<br>    protected $oauthRefreshToken = '';<br><br>    /**<br>     * OAuth constructor.<br>     *<br>     * @param array $options Associative array containing<br>     *                       `provider`, `userName`, `clientSecret`, `clientId` and `refreshToken` elements<br>     */<br>    public function __construct($options)<br>    \{<br>        $this->provider = $options['provider'];<br>        $this->oauthUserEmail = $options['userName'];<br>        $this->oauthClientSecret = $options['clientSecret'];<br>        $this->oauthClientId = $options['clientId'];<br>        $this->oauthRefreshToken = $options['refreshToken'];<br>    \}<br><br>    /**<br>     * Get a new RefreshToken.<br>     *<br>     * @return RefreshToken<br>     */<br>    protected function getGrant()<br>    \{<br>        return new RefreshToken();<br>    \}<br><br>    /**<br>     * Get a new AccessToken.<br>     *<br>     * @return AccessToken<br>     */<br>    protected function getToken()<br>    \{<br>        return $this->provider->getAccessToken(<br>            $this->getGrant(),<br>            ['refresh_token' => $this->oauthRefreshToken]<br>        );<br>    \}<br><br>    /**<br>     * Generate a base64-encoded OAuth token.<br>     *<br>     * @return string<br>     */<br>    public function getOauth64()<br>    \{<br>        //Get a new token if it's not available or has expired<br>        if (null === $this->oauthToken || $this->oauthToken->hasExpired